div.p:
sq_tail (App owns)
c
// App adds SQEs to the ring
sqe = &sqes[tail & mask];
fill_sqe(sqe);
// Release barrier ensures SQE writes visible
io_uring_smp_store_release(sq_tail, new_tail);

Kernel acquires tail:
c
tail = smp_load_acquire(sq_tail);
// Safe to read SQEs from head to tail
while (head != tail) {
process_sqe(&sqes[head & mask]);
head++;
}

sq_head (Kernel owns)
c
// Kernel advances after consuming SQEs
*sq_head = consumed_count;
// No barrier needed; kernel side only

App acquires head for space check:
c
head = smp_load_acquire(sq_head);
available = sq_entries - (tail - head);

cq_tail (Kernel owns)
c
// After posting CQE:
smp_store_release(cq_tail, new_tail);
// CQE data visible before tail update

App acquires tail to check for CQEs:
c
tail = smp_load_acquire(cq_tail);
if (tail != *cq_head) {
// CQEs available from head to tail
}

cq_head (App owns)
c
// After processing CQEs:
*cq_head = *cq_head + count;
// Kernel will acquire on next CQE post

Kernel checks space:
c
head = smp_load_acquire(cq_head);
space = cq_entries - (tail - head);
